/**
 * v3.28b Patch 1 — Customer card logo library.
 *
 * 51 customer logos bundled as base64 data URLs. Each entry has:
 *   - id: stable kebab-case identifier (used by editor saved projects)
 *   - name: human-readable brand name (used by editor search)
 *   - url: PNG data URL ready to drop into <img src=...>
 *
 * To use in renderer or editor:
 *   import { CUSTOMER_LOGOS, resolveCustomerLogoById } from './customer-logos';
 *   const url = resolveCustomerLogoById('hdfc');  // → data:image/png;base64,...
 *
 * Saved projects store the logo by id (not by URL) so the data URL never enters
 * the saved JSON — keeps project files tiny.
 */

