/** Lookup a logo's data URL by its id. Returns null if not found. */
export function resolveCustomerLogoById(id: string | null | undefined): string | null {
  if (!id) return null;
  const hit = CUSTOMER_LOGOS.find(l => l.id === id);
  return hit ? hit.url : null;
}

/** Lookup a logo by id. Returns null if not found. */
export function getCustomerLogo(id: string | null | undefined): CustomerLogo | null {
  if (!id) return null;
  return CUSTOMER_LOGOS.find(l => l.id === id) || null;
}
